const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { GraphQLSchema, GraphQLObjectType, GraphQLInt, GraphQLString, GraphQLList, GraphQLNonNull } = require('graphql');
const { Pool } = require('pg');

// --- PostgreSQL Setup ---
const pool = new Pool({
    user: 'your_user',        // Replace with your PostgreSQL username
    host: 'localhost',
    database: 'your_database', // Replace with your database name
    password: 'your_password', // Replace with your PostgreSQL password
    port: 5432,
});

// Test PostgreSQL connection
pool.query('SELECT NOW()')
    .then(res => console.log('PostgreSQL connected:', res.rows[0].now))
    .catch(err => console.error('Error connecting to PostgreSQL:', err));

// --- GraphQL Type Definitions ---

const AuthorType = new GraphQLObjectType({
    name: 'Author',
    fields: () => ({
        id: { type: GraphQLNonNull(GraphQLInt) },
        name: { type: GraphQLNonNull(GraphQLString) },
    }),
});

const PostType = new GraphQLObjectType({
    name: 'Post',
    fields: () => ({
        id: { type: GraphQLNonNull(GraphQLInt) },
        title: { type: GraphQLNonNull(GraphQLString) },
        content: { type: GraphQLNonNull(GraphQLString) },
        author: {
            type: AuthorType,
            // This resolver is called for each 'Post' object to fetch its associated 'Author'.
            // The 'source' argument here is the 'Post' object that was just resolved.
            resolve: async (source) => {
                // 'source' will contain the 'author_id' from the initial post query.
                const client = await pool.connect();
                try {
                    const res = await client.query('SELECT id, name FROM authors WHERE id = $1', [source.author_id]);
                    return res.rows[0]; // Return the author object
                } finally {
                    client.release();
                }
            },
        },
    }),
});

// --- Root Query Type ---

const RootQueryType = new GraphQLObjectType({
    name: 'Query',
    fields: {
        posts: {
            type: GraphQLList(PostType),
            resolve: async () => {
                const client = await pool.connect();
                try {
                    // Fetch posts. The 'author_id' is crucial for the PostType.author resolver.
                    const res = await client.query('SELECT id, title, content, author_id FROM posts');
                    return res.rows;
                } finally {
                    client.release();
                }
            },
        },
        post: {
            type: PostType,
            args: {
                id: { type: GraphQLNonNull(GraphQLInt) },
            },
            resolve: async (source, { id }) => {
                const client = await pool.connect();
                try {
                    const res = await client.query('SELECT id, title, content, author_id FROM posts WHERE id = $1', [id]);
                    return res.rows[0];
                } finally {
                    client.release();
                }
            },
        },
    },
});

// --- GraphQL Schema ---

const schema = new GraphQLSchema({
    query: RootQueryType,
});

// --- Express Server Setup ---

const app = express();
const PORT = 4000;

app.use(
    '/graphql',
    graphqlHTTP({
        schema: schema,
        graphiql: true, // Enable GraphiQL UI for easy testing
    })
);

app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}/graphql`);
    console.log('Use GraphiQL to test your queries, e.g.:');
    console.log(`
    query {
      posts {
        id
        title
        content
        author {
          id
          name
        }
      }
    }
    `);
    console.log(`
    query {
      post(id: 1) {
        id
        title
        author {
          name
        }
      }
    }
    `);
});

